<template><div class="page"><header class="page-head"><div><h1>Maintenance</h1><p>Operations controlees et progression en direct.</p></div><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></header><p v-if="error" class="notice error-text">{{ error }}</p><section class="action-grid"><article v-for="(meta,key) in actions" :key="key" class="panel action-card"><div><h2>{{ meta.label||key }}</h2><p>{{ meta.description }}</p></div><button class="primary" :disabled="running" @click="run(key)"><Play/>Executer</button></article></section><section v-if="current" class="panel run-panel"><div class="panel-head"><h2>{{ current.action }}</h2><span class="badge" :class="current.status==='error'?'failed':'available'">{{ current.status }}</span></div><progress :value="current.progress" max="100"></progress><pre>{{ (current.logs||[]).join('\n') }}</pre></section></div></template>
<script setup>import { onMounted,onUnmounted,ref } from "vue";import { Play,RefreshCw } from "@lucide/vue";import { api } from "@/api";const actions=ref({}),current=ref(null),loading=ref(false),running=ref(false),error=ref('');let timer;async function load(){loading.value=true;try{actions.value=await api('/api/maintenance/actions')}catch(e){error.value=e.message}finally{loading.value=false}}async function run(action){running.value=true;error.value='';try{const data=await api(`/api/maintenance/run/${action}`,{method:'POST'});poll(data.run_id)}catch(e){error.value=e.message;running.value=false}}async function poll(id){try{current.value=await api(`/api/maintenance/run/${id}`);if(['done','error'].includes(current.value.status)){running.value=false;return}timer=setTimeout(()=>poll(id),800)}catch(e){error.value=e.message;running.value=false}}onMounted(load);onUnmounted(()=>clearTimeout(timer));</script>
